class Solution:
    def minAddToMakeValid(self, s: str) -> int:
        open_needed = 0
        close_needed = 0
        for ch in s:
            if ch == '(':
                close_needed += 1
            else:
                if close_needed:
                    close_needed -= 1
                else:
                    open_needed += 1
        return open_needed + close_needed
```
